import { cleanupOutdatedCaches, precacheAndRoute } from "workbox-precaching"
import { clientsClaim } from "workbox-core"

import { initializeApp } from "firebase/app"
import { getMessaging, onBackgroundMessage } from "firebase/messaging/sw"

// Use the precache manifest generated by Vite
precacheAndRoute(self.__WB_MANIFEST)

// Clean up old caches
cleanupOutdatedCaches()

const jsonConfig = new URL(location).searchParams.get("config")
// Firebase config initialization
try {
    const firebaseApp = initializeApp(JSON.parse(jsonConfig))
    const messaging = getMessaging(firebaseApp)

    function isChrome() {
        return navigator.userAgent.toLowerCase().includes("chrome")
    }

    onBackgroundMessage(messaging, (payload) => {
        const data = payload.data || {}
        const notification = payload.notification || {}

        const notificationTitle = data.title || notification.title
        let notificationOptions = {
            body: data.body || notification.body || "",
        }

        if (data.image) {
            notificationOptions["icon"] = data.image
        }

        if (data.creation) {
            notificationOptions["timestamp"] = data.creation
        }
        let url = `${data.base_url}/raven/channel/${data.channel_id}`

        if (data.message_url) {
            url = data.message_url
        }

        if (isChrome()) {
            notificationOptions["data"] = {
                url: url,
            }
        } else {
            notificationOptions["actions"] = [
                {
                    action: url,
                    title: "View",
                },
            ]
        }
        self.registration.showNotification(notificationTitle, notificationOptions)
    })

    if (isChrome()) {
        self.addEventListener("notificationclick", (event) => {
            event.stopImmediatePropagation()
            event.notification.close()
            if (event.notification.data && event.notification.data.url) {
                clients.openWindow(event.notification.data.url)
            }
        })
    }
} catch (error) {
    console.log("Failed to initialize Firebase", error)
}

self.skipWaiting()
clientsClaim()
console.log("Service Worker Initialized")
